"use strict";(globalThis.webpackChunkassamese_app=globalThis.webpackChunkassamese_app||[]).push([[567],{567(e){e.exports=JSON.parse('{"title":"Lektion 5 \u2013 Kopulaverben","introduction":[{"erkl\xe4rung":"Die Verben wie Werden, Blieben und Sein haben eine Besondere funktion in Deutsch. Die sind Kopulaverben"},{"erkl\xe4rung":"Ein Kopulaverb ist ein Verb, das keine eigenst\xe4ndige lexikalische Bedeutung tr\xe4gt, sondern eine Verbindung (lateinisch: copula = Band, Verbindung) zwischen dem Subjekt und einem Pr\xe4dikativum herstellt \u2014 also einem Adjektiv oder Nomen, das eine Eigenschaft oder Identit\xe4t des Subjekts beschreibt"},{"erkl\xe4rung":"Die Analogen Verben(stamm) sind ho, thak und hoi "},{"erkl\xe4rung":"Ho und Thank werden konjugiert. Aber hoi wird nicht konjugiert. Siehe ()"}],"related":["/conjugation/table-2","/conjugation/table-4"]}')}}]);